+        let workflow = HandleOnErrorCassSearch::new();
+        let base = Detection {
+            rule_id: "claude_code.error.network".to_string(),
+            agent_type: AgentType::ClaudeCode,
+            event_type: "error.network".to_string(),
+            severity: Severity::Warning,
